// Default inputs: Porta Nuova, Mid-Range, Sell, 1000m², FAR 2.5, BCR 0.5, maxFloors 8, Flat, landPrice 2M, equity 30%, debt 70%, interest 4.5%, duration 24mo

const landArea = 1000, far = 2.5, bcr = 0.5, maxFloors = 8;
const footprint = landArea * bcr; // 500
const gfa = Math.min\(landArea * far, footprint * maxFloors\); // min\(2500, 4000\) = 2500
const netArea = gfa * 0.85; // 2125

console.log\('GFA:', gfa, 'Net Area:', netArea\);

// Costs
const baseCost = 2000; // Mid-Range Milano
const baseConstruction = gfa * baseCost; // 5,000,000
const mep = baseConstruction * 0.175;
const facade = baseConstruction * 0.10;
const hardCosts = baseConstruction + mep + facade;
console.log\('Hard Costs:', hardCosts\);

const softRate = 0.10 + 0.075 + 0.015 + 0.015 + 0.04 + 0.015 + 0.0075 + 0.075; // 0.3425
const softCosts = hardCosts * softRate;
console.log\('Soft Costs:', softCosts, 'Rate:', softRate\);

const landSiteCosts = 2000000 + 26000 + 10000; // 2,036,000
console.log\('Land & Site:', landSiteCosts\);

const totalBeforeFinancing = hardCosts + softCosts + landSiteCosts;
console.log\('Total before financing:', totalBeforeFinancing\);

const loanAmount = totalBeforeFinancing * 0.70;
const constructionInterest = loanAmount * 0.045 * \(24/12\);
const loanFees = loanAmount * 0.015;
const financingCosts = constructionInterest + loanFees;
console.log\('Financing:', financingCosts, '\(Interest:', constructionInterest, 'Fees:', loanFees, '\)'\);

const totalProjectCost = totalBeforeFinancing + financingCosts;
const equityInvested = totalProjectCost * 0.30;
console.log\('Total Project Cost:', totalProjectCost\);
console.log\('Equity Invested:', equityInvested\);

// Revenue \(Sell, Porta Nuova sale = 9500\)
const totalSales = netArea * 9500; // 2125 * 9500
const brokerFee = totalSales * 0.03;
const netSales = totalSales - brokerFee;
console.log\('Total Sales:', totalSales\);
console.log\('Net Sales:', netSales\);

const grossProfit = netSales - totalProjectCost;
const roi = \(grossProfit / totalProjectCost\) * 100;
const roe = \(grossProfit / equityInvested\) * 100;
const breakEven = totalProjectCost / netArea;

console.log\(''\);
console.log\('=== RESULTS ==='\);
console.log\('Gross Profit:', grossProfit.toFixed\(0\)\);
console.log\('ROI:', roi.toFixed\(1\) + '%'\);
console.log\('ROE:', roe.toFixed\(1\) + '%'\);
console.log\('Break-even per m²:', breakEven.toFixed\(0\)\);
console.log\('Market price per m²:', 9500\);
")

