// With fix: equity = total - loan
const totalBeforeFinancing = 10594437.5;
const loanAmount = totalBeforeFinancing * 0.70; // 7,416,106
const financingCosts = 778691.16;
const totalProjectCost = totalBeforeFinancing + financingCosts; // 11,373,129
const equityFixed = totalProjectCost - loanAmount; // equity covers the rest
const netSales = 19581875;
const grossProfit = netSales - totalProjectCost;
const months = 24;

const roi = \(grossProfit / totalProjectCost\) * 100;
const roe = \(grossProfit / equityFixed\) * 100;
const annualizedRoi = \(Math.pow\(1 + grossProfit / totalProjectCost, 12 / months\) - 1\) * 100;
const annualizedRoe = \(Math.pow\(1 + grossProfit / equityFixed, 12 / months\) - 1\) * 100;

console.log\('Equity \(fixed\):', equityFixed.toFixed\(0\), '\(was', \(totalProjectCost * 0.30\).toFixed\(0\), '\)'\);
console.log\('ROI total:', roi.toFixed\(1\) + '%'\);
console.log\('ROE total:', roe.toFixed\(1\) + '%'\);
console.log\('ROI annualized:', annualizedRoi.toFixed\(1\) + '%'\);
console.log\('ROE annualized:', annualizedRoe.toFixed\(1\) + '%'\);
")

Bash(node -e "
// Test two different rent scenarios
function calcRent\(district, rent, landPrice\) {
  const landArea = 1000, far = 2.5, bcr = 0.5;
  const footprint = landArea * bcr;
  const gfa = Math.min\(landArea * far, footprint * 8\);
  const netArea = gfa * 0.85;

  const baseConstruction = gfa * 2000;
  const hardCosts = baseConstruction * 1.275;
  const softCosts = hardCosts * 0.3275; // no marketing for rent
  const landSiteCosts = landPrice + 36000;
  const totalBefore = hardCosts + softCosts + landSiteCosts;
  const loanAmount = totalBefore * 0.70;
  const financing = loanAmount * 0.045 * 2 + loanAmount * 0.015;
  const totalCost = totalBefore + financing;

  const grossRent = netArea * rent * 12 * 0.92;
  const noi = grossRent * 0.75;

  const wacc = 0.30 * 0.15 + 0.70 * 0.045 * 0.76;

  let dcfSum = 0;
  for \(let y = 1; y <= 10; y++\) {
    const cf = noi * Math.pow\(1.02, y\);
    dcfSum += cf / Math.pow\(1 + wacc, y\);
  }
  const tv = \(noi * Math.pow\(1.02, 11\)\) / \(wacc - 0.02\);
  const dtv = tv / Math.pow\(1 + wacc, 10\);
  const npv = dcfSum + dtv - totalCost;

  console.log\(district + ': NOI=' + noi.toFixed\(0\) + ' NPV=' + npv.toFixed\(0\) + ' WACC=' + \(wacc*100\).toFixed\(2\) + '%'\);
}

calcRent\('Porta Nuova', 30, 2000000\);
calcRent\('Lambrate', 17, 2000000\);
calcRent\('Brera', 33, 2000000\);
")
